UPDATE `blog_column_article` SET `deleted_at`='2026-05-08 23:59:27',`updated_at`='2026-05-08 23:59:27' WHERE `column_id`=9200009;


UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:59:27',`updated_at`='2026-05-08 23:59:27' WHERE `topic_id` IN (9309001, 9309002, 9309003, 9309004, 9309005, 9309006);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('代码规范', '开发流程', '开发理论', '开源协议', '方法论', '架构设计', '源码解析', '系统认证', '设计模式');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200009);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9309001, 9309002, 9309003, 9309004, 9309005, 9309006);

